import numpy as np

def create_superposition(values, n_qubits):
    dim = 2 ** n_qubits
    state = np.zeros(dim, dtype=complex)

    for v in values:
        if 0 <= v < dim:
            state[v] = 1.0

    norm = np.linalg.norm(state)
    if norm > 0:
        state = state / norm

    return state

def measure_probabilities(state):
    return np.abs(state) ** 2

state = create_superposition([0, 2, 4, 6], 3)
probs = measure_probabilities(state)
print('Even numbers superposition:')
for i, p in enumerate(probs):
    if p > 0.01:
        print(f'  |{format(i, "03b")}⟩: {p:.4f}')

print(f'\nTotal probability: {sum(probs):.4f}')
print(f'Each value probability: {1/4:.4f} (expected for 4 values)')
